const TT = (moduleId, id, num, name, slug, tags, hookQ, hookI, blocks, rel, gaps, diff, svgStr, vaType) => ({
  trackKey: TRACK_KEY, moduleId, topicId: id, topicNumber: num, name, slug,
  metadata: { estimated_minutes: 50, difficulty: 4, prerequisites: [], tags },
  hook: { question: hookQ, insight: hookI },
  teaching: { blocks, visual_aid: { type: vaType, svg: svgStr, alt_text: `${name} architecture diagram.` } },
  interviewRelevance: rel, commonGaps: { gaps },
  prerequisites: [], estimatedMinutes: 50, difficulty: diff, xpReward: 80, visualizer: null,
});
const C = (section, heading, body) => ({ kind: "concept", section, heading, body });
const K = (section, heading, body) => ({ kind: "code", section, heading, body });
const G = (id, w, r, d) => ({ gap_id: id, what_students_get_wrong: w, remediation: r, detection_pattern: d });

const TOPICS = [
  // ───────────────── UPTIME / STATUS MONITORING SERVICE ─────────────────────
  TT("sysd_m17", "sysd_m17_t8", 8, "Design an Uptime / Status Monitoring Service", "design-uptime-monitoring",
    ["case-study", "monitoring", "alerting", "distributed-checks"],
    "You watch thousands of customers' websites and APIs and must page them the moment one goes down — but NOT page them because one of your probes had a flaky network hiccup. How do you reliably detect downtime from afar, avoid false alarms, and show a trustworthy status page?",
    "Distributed PROBES in multiple regions periodically check monitored endpoints (HTTP/TCP/ping) and record results; a target is declared DOWN only when failures are CONFIRMED from MULTIPLE locations (so one probe's network glitch isn't a false alarm), and ALERTS fire on state CHANGES (down/up) through notification channels — while a STATUS PAGE shows current state + historical uptime from time-series results. Multi-location checking with false-positive avoidance + alerting/status/scale are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: MONITOR endpoints (websites/APIs/servers) by periodically CHECKING them (HTTP/TCP/ping); detect DOWNTIME and recovery; ALERT the owner on incidents (multiple channels); show a STATUS PAGE (current state, incident history) and track UPTIME % / response time. Non-functional: ACCURACY / LOW FALSE POSITIVES (don't alert when the target is actually up — a probe's own network issue must not page someone at 3am), FAST detection + alerting (catch downtime quickly), SCALE (many monitors, frequent checks), and reliability of the monitor itself. Clarify scope: an uptime/status monitoring service (Pingdom / UptimeRobot / StatusPage style). The defining challenges: (1) RELIABLE DETECTION from OUTSIDE the target with LOW FALSE POSITIVES — a single probe failing to reach a site could be the SITE being down OR the PROBE's network path having a problem; alerting on one failed check from one location causes false alarms (alert fatigue), so you must CONFIRM downtime from MULTIPLE locations / retries before declaring DOWN; (2) ALERTING on state TRANSITIONS (alert when it goes down, and when it recovers — not repeatedly while it stays down) with dedup/escalation to avoid alert fatigue; and (3) SCALE — scheduling and running frequent checks for many monitors, and storing results (time-series) for uptime %/status pages. So the design centers on distributed multi-location checking (with false-positive avoidance) + alerting + status/uptime storage at scale."),
      K("estimation", "Capacity estimation (with numbers)",
        "Monitors: many (thousands+), each checked e.g. every 1 min from multiple regions.\n  -> high steady check volume ; distribute probes across regions.\nDetection: a single failed check could be the probe's network -> CONFIRM from multiple probes.\nState: per monitor (up/down) ; alert on TRANSITIONS only (not every failed check).\nResults: time-series of check outcomes -> uptime %, latency, status page history.\nTakeaway: distributed multi-region probes + multi-location confirmation (no false positives)\n+ alert on state change + time-series uptime storage, scheduled at scale."),
      C("hld", "High-level design",
        "Distributed PROBE workers in MULTIPLE geographic regions periodically CHECK each monitored endpoint (HTTP request / TCP connect / ping, on the monitor's interval), recording the result (up/down, latency, status code). A monitor's STATE is determined not by a single check but by CONFIRMATION: a target is declared DOWN only when checks FAIL from MULTIPLE locations (and/or after retries) — so a single probe's transient network problem (the probe is broken, not the site) doesn't trigger a false alarm; conversely recovery is confirmed similarly. On a STATE TRANSITION (up→down or down→up), an ALERT is fired through the owner's configured channels (email/SMS/push/Slack/PagerDuty) — alerting on the TRANSITION (not every failed check) plus dedup/escalation avoids alert fatigue. Check RESULTS are stored as TIME-SERIES, powering UPTIME % calculations, response-time graphs, and a STATUS PAGE (current status + incident history, public or private). A SCHEDULER dispatches the many checks across the probe fleet at their intervals. Trace it: probe each region checks site X every minute -> all fail -> confirm DOWN from 3 regions -> fire 'down' alert -> record incident; later checks pass from multiple -> confirm UP -> 'recovered' alert -> status page + uptime % updated. Multi-region probes + multi-location down-confirmation + alert-on-transition + time-series uptime/status is the shape."),
      K("api", "API / flow",
        "configure: monitor { endpoint, type (HTTP/TCP/ping), interval, regions, alert channels }\nscheduler: dispatch checks across multi-region probes at each interval\nprobe: check endpoint -> record result (up/down, latency, code)\ndetection: declare DOWN only when CONFIRMED from MULTIPLE locations (+ retries) -> no false positive\nalert: on STATE TRANSITION (down/up) -> notify via channels (dedup/escalation)\nstore: time-series results -> uptime %, latency, status page (current + history)"),
      K("data_model", "Data model",
        "monitors: endpoint, type, interval, regions, alert config, current state\ncheck results: (monitor, region, ts, up/down, latency, code) -> time-series\nstate: per-monitor up/down (confirmed) ; transitions trigger alerts\nincidents: down periods (start/end) -> status page history + uptime %\nalerts: channels + dedup/escalation state"),
      C("deep_dive", "Deep dive: distributed checking & avoiding false positives",
        "The core correctness challenge is detecting REAL downtime without false alarms, from OUTSIDE the target. THE PROBLEM: you check a site from a probe, and the check FAILS — but that could mean (a) the SITE is actually down, or (b) the PROBE's own network path to the site has a problem (the probe is the one with the issue, the site is fine). If you ALERT on a single failed check from a single location, you'll page customers for non-incidents (the probe's flaky network), causing ALERT FATIGUE and eroding trust — false positives are a top failure mode for monitoring. THE SOLUTION — MULTI-LOCATION CONFIRMATION: run probes in MULTIPLE geographic regions and declare a target DOWN only when the check FAILS from MULTIPLE locations (a quorum) — if one probe sees a failure but others see the site up, it's the probe's problem, not the site's, so DON'T alert; only when SEVERAL independent vantage points agree the site is unreachable is it genuinely down. Combine with RETRIES (a single transient blip is retried before counting) and a confirmation threshold/window. This dramatically cuts false positives. CHECK TYPES: HTTP (status code, content match, latency), TCP connect, ping/ICMP, and richer checks (response time SLA, keyword presence, SSL expiry) — depending on what 'up' means for the monitor. INTERVALS: checks run on a configured interval (e.g. every minute), trading detection speed vs cost/load. The detection logic maintains the monitor's confirmed STATE and only changes it on confirmed transitions. So distributed multi-region probes + requiring MULTI-LOCATION (quorum) confirmation + retries before declaring down (so a probe's own network issue isn't a false alarm) is the detection core interviewers probe (the wrong instinct is 'alert when a check fails')."),
      C("deep_dive", "Deep dive: alerting, status/uptime & scale",
        "Around detection sit alerting, status reporting, and scaling the checks. ALERTING ON TRANSITIONS: alerts fire on STATE CHANGES — when a monitor goes DOWN (confirmed) and when it RECOVERS (up) — NOT on every failed check while it stays down (which would spam). Alerts go through the owner's configured CHANNELS (email/SMS/push/Slack/PagerDuty/webhook), with DEDUP (one alert per incident, not per check) and often ESCALATION (notify, then escalate if unacknowledged) and configurable rules (alert only after N minutes down, maintenance windows to suppress) — all to combat ALERT FATIGUE so alerts stay trustworthy/actionable. STATUS PAGE + UPTIME: check RESULTS are stored as TIME-SERIES (per monitor, per region: up/down, latency over time) — the metrics/TSDB pattern — from which you compute UPTIME % (e.g. 99.95% this month), response-time trends, and an incident history; a STATUS PAGE (public or internal) shows the CURRENT status of services + ongoing/past incidents (so users/customers see at a glance whether something is down) — both auto-detected and manually-posted incidents. SCALE: many monitors × frequent intervals × multiple regions = a large, steady volume of scheduled checks — a SCHEDULER distributes checks across the probe fleet at their due times (a job-scheduling problem), probes run them in parallel, and results stream into the time-series store; the system scales by adding probes and sharding monitors. RELIABILITY OF THE MONITOR: the monitoring system itself must be highly available and independent of what it monitors (don't host your monitor on the same infra) — 'who watches the watcher'. So alert-on-transition with dedup/escalation (anti-fatigue) + time-series-backed uptime %/status page + a scalable scheduler distributing checks across a probe fleet is the operational core interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "FALSE POSITIVES are the cardinal risk -> multi-location confirmation + retries before alerting (a probe's network issue isn't an outage). ALERT FATIGUE -> alert on transitions only + dedup (one per incident) + escalation + thresholds/maintenance windows. CHECK SCHEDULING at scale -> a scheduler distributing many checks across a probe fleet at their intervals; sharding. DETECTION SPEED vs COST -> shorter intervals catch downtime faster but cost more checks/load on targets. MULTI-REGION -> probes in several regions (more accuracy + global view, more infra). MONITOR RELIABILITY -> the monitoring system must be independent + HA. Trade-offs: multi-location confirmation (few false positives — slightly slower detection / more probes) vs single-check alerting (instant — false-alarm storms); alert on transition + dedup (trustworthy, low-noise — must track state) vs alert per failed check (simple — fatigue); short interval (fast detection — more checks/cost/target load) vs long (cheap — slower detection); time-series store (uptime %, trends, status history — storage) vs current-state-only (cheap — no history/uptime); distributed probes (accurate global view — coordination) vs single-location (simple — blind to regional issues + false positives). Closing signal: distributed multi-region probes checking endpoints on intervals, declaring DOWN only on MULTI-LOCATION confirmation (+ retries) to avoid false positives, alerting on confirmed state TRANSITIONS via channels with dedup/escalation (anti-fatigue), and storing time-series results for uptime % + a status page — reliable, low-noise, scalable monitoring whose own availability is independent of the monitored systems."),
      C("deep_dive", "Deep dive: incidents, SLAs, integrations & operations",
        "Operationally a monitoring service is trust-critical alerting + reporting infrastructure. Incident lifecycle: a confirmed down→up span is an INCIDENT (start/end, affected monitor, root signals) — tracked, shown on the status page, and used for uptime/SLA reporting; support manual incident posting + updates (for planned maintenance or known issues) alongside auto-detected ones. SLA/uptime computation: from time-series check results compute uptime % over periods (day/month), excluding maintenance windows, and SLA breach reporting — accuracy matters (it's contractual for some). Alert routing & on-call: integrate with on-call/escalation tools (PagerDuty/Opsgenie), schedules, acknowledgement, and escalation chains; rate-limit/group alerts; quiet hours/maintenance suppression — all to keep alerts actionable. Check sophistication: beyond up/down — response time thresholds (SLA), content/keyword assertions, transaction/synthetic checks (multi-step user flows), API checks, SSL cert expiry, and DNS — 'up' is often more than a 200. Probe network: a global fleet of probes (own + cloud regions) for geographic coverage and to distinguish regional outages (a site up in the US but down in Asia); confirm across them. Self-monitoring & independence: the monitoring system must be HA and hosted independently of monitored infra (so it survives when the customer's infra fails); meta-monitoring watches the probes. Status page delivery: public status pages must themselves be highly available + CDN-served (they're hit hardest exactly when things are down) — often static/edge-hosted, decoupled from the rest. Subscriptions: users subscribe to status updates (notify on incidents). Scale: scheduler + probe fleet + time-series store scale independently; shard monitors. Observability of itself: probe health, check throughput, false-positive/alert rates, and detection latency are the SLOs. The spine holds: multi-region confirmed checking + transition alerting (escalation, anti-fatigue) + time-series uptime/incidents + an independently-hosted, CDN-served status page, integrated with on-call."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'A check fails — do you alert?' not from a single probe — that could be the PROBE's network, not the site; confirm DOWN from MULTIPLE locations (+ retries) before alerting (avoids false positives / alert fatigue). 'Avoid alert spam?' alert on state TRANSITIONS only (down, then recovered), dedup to one per incident, escalation if unacknowledged, thresholds + maintenance windows. 'Detect downtime fast?' shorter check intervals (trading cost/target load) + multi-region probes. 'Uptime % / status page?' store check results as TIME-SERIES, compute uptime % + latency trends + incident history; show current status. 'Scale many monitors?' a scheduler distributes checks across a probe fleet at their intervals; shard monitors; results stream to the TSDB. 'Distinguish a regional outage?' multi-region probes (up in US, down in Asia). 'What does up mean?' configurable checks — HTTP status/content, response-time SLA, TCP, SSL expiry, synthetic transactions. 'The monitor itself?' must be HA and hosted INDEPENDENTLY of monitored infra; the status page is CDN-served (hit hardest during outages). 'On-call?' integrate escalation/acknowledgement (PagerDuty). Each returns to the spine: multi-region confirmed checks + transition alerting (anti-fatigue) + time-series uptime/status, scheduled at scale, independently hosted."),
    ],
    "An uptime/status monitoring service tests reliable external downtime detection with LOW FALSE POSITIVES — distributed multi-region probes that declare DOWN only on MULTI-LOCATION confirmation (+ retries), so a probe's own network glitch isn't a false alarm — plus alert-on-state-TRANSITION with dedup/escalation (anti-fatigue), time-series-backed uptime %/status page, a scalable scheduler across a probe fleet, and an independently-hosted status page. The signal is multi-location confirmation (no false positives) + transition alerting + uptime/status, not 'alert when a single check fails'.",
    [
      G("single_check_alert", "Alerting on a single failed check from one probe.", "Confirm DOWN from MULTIPLE locations (+ retries) before alerting — a single probe's failure may be its own network, not the site (false positive).", "Pages the owner whenever any one probe's check fails; flaky-probe false alarms."),
      G("alert_per_failure", "Alerting on every failed check while a target stays down.", "Alert on state TRANSITIONS only (down, recovered) + dedup (one per incident) + escalation — avoid alert fatigue.", "Sends repeated alerts each interval the target is down; alert spam."),
      G("no_timeseries", "Only tracking current up/down with no history.", "Store check results as time-series to compute uptime %, latency trends, and incident history for the status page.", "No historical results; can't show uptime % or incident history."),
    ],
    0.5, DIAG.uptime, "Uptime / status monitoring architecture"),

  // ─────────────────────── TWO-SIDED MARKETPLACE ───────────────────────────
  TT("sysd_m19", "sysd_m19_t7", 7, "Design a Two-Sided Marketplace", "design-two-sided-marketplace",
    ["case-study", "marketplace", "matching", "trust"],
    "A marketplace has two kinds of users who need each other — sellers and buyers, drivers and riders, hosts and guests — and it's worthless to either side until the other side shows up. Beyond the search and payments, how do you design for the chicken-and-egg liquidity problem and the trust between strangers?",
    "A two-sided marketplace connects SUPPLY (sellers/providers + their listings) and DEMAND (buyers searching/matching), with TRANSACTIONS (payments — often escrow + a platform commission) and two-way RATINGS/trust. The defining challenges beyond plumbing are balancing the two sides (LIQUIDITY — the chicken-and-egg cold start) and TRUST between strangers (ratings, payments, safety). It composes search + matching + payments + reviews. Two-sided dynamics/matching + transactions/trust/payments are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: support TWO user types — SUPPLY (sellers/providers who list offerings/inventory) and DEMAND (buyers who search/browse and purchase); let demand DISCOVER and MATCH with supply (search/listings/matching); process TRANSACTIONS (payments, the platform takes a COMMISSION); enable TRUST via two-way RATINGS/reviews; handle disputes. Non-functional: good SEARCH/discovery + MATCHING (connect demand to the right supply), TRUST/safety (strangers transacting), reliable PAYMENTS (often with escrow), and scaling BOTH sides. Clarify scope: a general two-sided marketplace (the pattern behind eBay/Etsy, Uber, Airbnb, Upwork, etc. — abstracting their common structure). It COMPOSES earlier designs — SEARCH (find listings), MATCHING (connect demand to supply, e.g. geo/ranking), PAYMENTS (the checkout/payment + escrow flow), and REVIEWS/trust — but the DISTINCTIVE marketplace challenges are: (1) TWO-SIDED DYNAMICS / LIQUIDITY — the platform is only valuable when BOTH sides are present (buyers won't come without sellers and vice versa — the chicken-and-egg / cold-start problem), so you must bootstrap and balance SUPPLY and DEMAND (liquidity); and (2) TRUST between strangers — buyers and sellers who don't know each other must trust the transaction, requiring ratings/reviews, secure payments (escrow so neither side is cheated), identity/verification, and trust-&-safety (fraud, disputes). So the design centers on the two-sided dynamics + matching, and the transaction/trust/payment layer that makes strangers transact safely."),
      K("estimation", "Capacity estimation (with numbers)",
        "Two sides: supply (listings) + demand (buyers) -> both must scale + be balanced (liquidity).\nDiscovery: demand searches/matches against supply -> search + matching (geo/category/ranking).\nTransactions: payments with a platform COMMISSION ; often ESCROW (hold until delivered).\nTrust: two-way ratings/reviews + verification + dispute handling (strangers transacting).\nCold start: chicken-and-egg -> bootstrap one side / seed supply / niche down.\nTakeaway: balance + match supply<->demand (liquidity), and make strangers transact safely\n(escrow payments + commission + two-way ratings + trust/safety)."),
      C("hld", "High-level design",
        "SUPPLY side: providers create LISTINGS / offer inventory or availability (the supply catalog), managed via a seller/provider experience. DEMAND side: buyers SEARCH/browse and the platform MATCHES them to relevant supply (search index + ranking + matching logic — e.g. by category, location, price, quality — reusing the search/recsys/proximity patterns per the domain). When a buyer commits, a TRANSACTION runs: PAYMENT is processed (often via ESCROW — the platform holds the buyer's funds and releases them to the seller after the goods/service are delivered/confirmed, protecting both sides), the platform takes a COMMISSION/fee, and an order/booking is created (the checkout/saga pattern). TRUST is built with two-way RATINGS/REVIEWS (buyers rate sellers AND sellers rate buyers), identity VERIFICATION, and a TRUST-&-SAFETY layer (fraud detection, content moderation, dispute resolution). The platform must continuously balance SUPPLY and DEMAND (LIQUIDITY) — ensuring enough supply for demand and enough demand for supply — and bootstrap it (the cold-start problem). Trace it: seller lists an item -> indexed; buyer searches -> matched to listings -> buys -> escrow payment (platform fee) -> seller ships -> buyer confirms -> funds released -> both rate each other. Supply (listings) + demand (search/matching) -> transaction (escrow payment + commission) -> two-way ratings, atop liquidity-balancing + trust/safety, is the shape."),
      K("api", "API / flow",
        "supply: create/manage listings (inventory/availability) -> catalog + search index\ndemand: search/browse -> matching (category/geo/price/quality ranking) -> select\ntransaction: payment (ESCROW: hold -> release on delivery) + platform COMMISSION -> order\ntrust: two-way ratings/reviews ; identity verification ; dispute resolution\nplatform: balance supply<->demand (liquidity) ; bootstrap (cold start) ; trust & safety (fraud/moderation)"),
      K("data_model", "Data model",
        "users: supply (sellers/providers) + demand (buyers) — two roles (can be both)\nlistings: supply catalog (inventory/availability) -> search index\ntransactions: orders/bookings + payment (escrow state) + commission\nratings/reviews: two-way (buyer<->seller) -> trust/reputation\ntrust & safety: verification, fraud signals, disputes\nliquidity metrics: supply/demand balance per market/segment"),
      C("deep_dive", "Deep dive: two-sided dynamics, liquidity & matching",
        "The distinctive challenge is the TWO-SIDED nature and its LIQUIDITY problem. NETWORK EFFECTS / CHICKEN-AND-EGG: a marketplace creates value by connecting two sides, but each side only shows up if the OTHER is present — buyers won't come without enough sellers/selection, and sellers won't come without enough buyers/demand. This is the COLD-START / chicken-and-egg problem: at launch (or in a new market/category) you have neither side, and the platform is useless. STRATEGIES to bootstrap: seed one side first (often SUPPLY — recruit sellers/inventory so there's something to attract buyers, e.g. seed listings), NICHE DOWN (start in one city/category to reach liquidity in a small market before expanding — Uber/Airbnb city-by-city), subsidize one side, or fake/manual supply initially. LIQUIDITY is the ongoing health metric: enough supply to satisfy demand quickly (a buyer finds what they want) AND enough demand to keep supply engaged (sellers make sales) — a thin market (low liquidity) frustrates both and churns them. The platform continuously monitors and BALANCES supply/demand (per market/segment/geo), using incentives, pricing (e.g. surge pricing to balance real-time supply/demand in ride-sharing), and growth tactics. MATCHING / DISCOVERY: connecting demand to the right supply is core — SEARCH (find listings), RANKING/recommendations (surface the best matches), and domain-specific MATCHING (geo proximity for local services, skill matching for labor, availability for bookings) — reusing the search/recsys/proximity/matching patterns, but tuned to maximize successful matches (liquidity in action: a search that finds a good match = a transaction). So understanding the two-sided/liquidity dynamics (chicken-and-egg, bootstrapping, balancing supply/demand) + effective matching/discovery to connect the sides is the distinctive core interviewers probe (it's what makes a marketplace different from a single-sided app)."),
      C("deep_dive", "Deep dive: transactions, trust & payments",
        "The other distinctive challenge is enabling STRANGERS to transact SAFELY — trust + payments. THE TRUST PROBLEM: buyers and sellers don't know each other, so each fears being cheated (buyer: pay and get nothing/something bad; seller: deliver and not get paid) — without trust, transactions don't happen. The platform PROVIDES trust as a service. PAYMENTS WITH ESCROW: rather than buyer paying seller directly, the platform mediates — it collects the buyer's payment and HOLDS it in ESCROW, releasing it to the seller only after the good/service is DELIVERED/confirmed (and supports refunds/chargebacks if not) — so neither side has to trust the other, just the platform; the platform takes its COMMISSION from the transaction (its revenue model). This payment flow (collect, hold, release, payout, with disputes) is a careful financial workflow (the payment/checkout/saga + subscription-billing-grade accuracy patterns). RATINGS / REPUTATION: two-way RATINGS and reviews (buyers rate sellers AND sellers rate buyers) build REPUTATION over time, so participants can assess each other before transacting — a self-reinforcing trust mechanism (good actors accumulate good reputation; bad actors are surfaced); reputation is central to marketplace trust. IDENTITY & VERIFICATION: verifying users (KYC/identity, for higher-trust marketplaces) reduces fraud and fake accounts. TRUST & SAFETY: fraud detection (the fraud-detection design — scams, fake listings, payment fraud), content moderation (the moderation design — prohibited/fake listings), and DISPUTE RESOLUTION (when a transaction goes wrong, the platform adjudicates — refund, penalize) — a major operational function. SAFETY for physical marketplaces (background checks, in-person safety). So escrow-mediated payments + commission + two-way reputation/ratings + verification + trust-&-safety/disputes is the transaction-trust core that lets strangers transact — exactly what interviewers probe (it's why a marketplace is more than search + checkout)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "LIQUIDITY / chicken-and-egg — the existential challenge -> bootstrap one side (usually supply), niche down, subsidize, balance supply/demand continuously. MATCHING quality — bad matches = no transactions -> good search/ranking/matching tuned for successful matches. TRUST/FRAUD — strangers transacting -> escrow payments, two-way ratings, verification, fraud detection, dispute resolution. PAYMENT complexity — escrow/payouts/refunds/commission across many sellers -> a robust payment workflow (split payments, marketplace payouts, tax). DISINTERMEDIATION — both sides may try to transact off-platform to avoid fees (a marketplace risk) -> value-adds that keep them on-platform. Trade-offs: escrow (trust, protects both — platform holds funds, complexity) vs direct payment (simple — neither side trusts); two-way ratings (mutual trust — gaming/retaliation risk) vs one-way; seed supply first (something to attract demand — manual effort) vs demand-first (rarely works — nothing to buy); niche/city-by-city launch (reach liquidity fast in a small market — slower total growth) vs broad launch (big but thin/illiquid everywhere); take a commission (revenue — disintermediation incentive) vs other models. Closing signal: a two-sided platform connecting SUPPLY (listings) and DEMAND (search/matching) with escrow-mediated PAYMENTS (+ commission) and two-way RATINGS/verification/trust-&-safety, designed around LIQUIDITY (bootstrap the chicken-and-egg by seeding supply / niching down, and continuously balance supply/demand) — composing search + matching + payments + reviews, with the two-sided dynamics and stranger-trust as the distinctive concerns."),
      C("deep_dive", "Deep dive: payments infra, disintermediation, growth & operations",
        "Operationally a marketplace is search + matching + a financial + trust platform. Marketplace payments infrastructure: beyond a simple charge, you need SPLIT payments / payouts (collect from buyer, deduct commission, PAY OUT to the seller — to many sellers, often via a payments provider's marketplace/Connect APIs), escrow timing, refunds/chargebacks, tax handling (collect/remit), multi-currency, and seller onboarding/KYC for payouts — billing-grade accuracy (the payment + subscription-billing patterns). Trust & safety operations: fraud detection (fake listings, payment fraud, account takeover — the fraud design), content moderation (prohibited/counterfeit listings — the moderation design), identity verification, dispute resolution (adjudicate buyer/seller conflicts, refund policies), and safety (for in-person/physical marketplaces). Reputation systems: two-way ratings, review integrity (prevent fake/retaliatory reviews), and surfacing reputation in ranking. Disintermediation: both sides may try to take the deal off-platform to dodge fees — counter with on-platform value (payments protection, communication, guarantees) and detection. Growth & liquidity ops: monitor liquidity per market/segment (search-to-transaction rates, supply/demand ratios), targeted growth on the constrained side, incentives, and dynamic pricing (where applicable) to balance real-time supply/demand. Search/matching & recommendations: tuned to maximize matches (the recsys/search patterns), personalization, and ranking that balances buyer relevance with marketplace goals (don't over-concentrate on top sellers — fairness/ecosystem health). Categories/verticals: horizontal vs vertical marketplaces; category-specific matching. Scale: supply catalog + search index + transactions + trust systems scale independently; sharded by user/market. Observability: liquidity metrics (match/transaction rates, supply-demand balance), payment success, fraud/dispute rates, and search/matching quality are the SLOs. The spine holds: supply listings + demand search/matching + escrow-split payments/payouts (+ commission) + two-way reputation/trust-&-safety, engineered around liquidity and stranger-trust, with marketplace-payments infra and growth ops."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'What makes a marketplace hard beyond search + checkout?' the TWO-SIDED dynamics — it's only valuable when BOTH sides are present (chicken-and-egg/cold start), so you must bootstrap and balance supply/demand (LIQUIDITY); and stranger-TRUST. 'How do you solve cold start?' seed one side first (usually supply, so there's selection), niche down (one city/category to reach liquidity in a small market, then expand), subsidize, or manual supply. 'How do strangers trust each other?' the platform provides trust — ESCROW payments (hold buyer funds, release on delivery, so neither must trust the other), two-way RATINGS/reputation, identity verification, fraud detection, and dispute resolution. 'Payments?' collect from buyer, take a COMMISSION, escrow + payout to the seller (split payments/marketplace payouts), with refunds/disputes — billing-grade. 'Connect demand to supply?' search + ranking + domain matching (geo/skill/availability) tuned to maximize successful matches. 'People transacting off-platform (disintermediation)?' counter with on-platform value + detection. 'Balance supply/demand in real time?' incentives + dynamic/surge pricing where applicable. 'Reuses which designs?' search, recsys/proximity/matching, payments/checkout, reviews, fraud, moderation. Each returns to the spine: supply + demand + matching + escrow payments/commission + two-way trust, engineered around liquidity + stranger-trust."),
    ],
    "A two-sided marketplace tests the distinctive concerns beyond search/checkout: the TWO-SIDED dynamics + LIQUIDITY (chicken-and-egg cold start — bootstrap by seeding supply / niching down, and continuously balance supply/demand) and stranger-TRUST (escrow-mediated payments + commission, two-way ratings/reputation, verification, fraud/moderation, dispute resolution), composing search + matching + payments + reviews. The signal is liquidity/two-sided dynamics + trust/escrow-payments, not just listing search and a checkout.",
    [
      G("ignore_liquidity", "Treating it as a single-sided app, ignoring the two-sided cold start.", "Design for liquidity — bootstrap the chicken-and-egg (seed supply, niche down) and continuously balance supply/demand.", "Builds listings + search but no plan for getting both sides / balancing supply-demand."),
      G("no_trust_escrow", "Letting strangers pay each other directly with no trust layer.", "Mediate trust — escrow payments (hold, release on delivery), two-way ratings/reputation, verification, fraud detection, disputes.", "Buyer pays seller directly; no escrow, ratings, or dispute handling; rampant fraud."),
      G("simple_payment", "Treating payments as a single buyer→platform charge.", "Marketplace payments — collect, take commission, escrow + payout to sellers (split payments), refunds/disputes, billing-grade.", "No commission/payout/escrow model; can't pay sellers or handle refunds."),
    ],
    0.6, DIAG.marketplace, "Two-sided marketplace architecture"),

  // ──────────────────── PACKAGE REGISTRY (npm / Docker) ─────────────────────
  TT("sysd_m19", "sysd_m19_t5", 5, "Design a Package Registry (npm / Docker)", "design-package-registry",
    ["case-study", "registry", "immutability", "cdn"],
    "Millions of developers publish library versions and billions of times a day machines download them to build software — and a version, once published, must be byte-for-byte identical forever (or builds become non-reproducible and supply-chain attacks slip in). How do you design a package/artifact registry?",
    "Packages are versioned, IMMUTABLE ARTIFACTS stored in object storage and served via CDN (downloads are massively read-heavy); a metadata DB holds versions + dependency info; PUBLISHING is authenticated with integrity (checksums/signing) and enforces immutability (a published version can never be overwritten); dependency resolution works from the metadata. Like an object store + CDN with immutability + dependency metadata + supply-chain security. Immutable artifact storage/serving + metadata/dependency resolution/publishing are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: PUBLISH packages (versioned artifacts — npm tarballs, Docker images, etc.) with METADATA; DOWNLOAD/install a package version and its DEPENDENCIES; search/discover packages; manage versions. Non-functional: massive DOWNLOAD READ scale (packages are downloaded billions of times for builds/installs — extremely read-heavy), IMMUTABILITY (a published version must NEVER change — builds depend on it being identical forever), INTEGRITY/security (verify artifacts aren't tampered — supply-chain security), dependency METADATA correctness, and high availability (the build/deploy pipelines of the world depend on it). Clarify scope: a package/artifact registry (npm, PyPI, Docker Hub, Maven Central style). The defining characteristics: (1) it's overwhelmingly READ-HEAVY — a package is published once but downloaded enormous numbers of times (every CI build, every install) — so downloads must be served cheaply at scale, naturally via CDN/caching; (2) IMMUTABILITY is paramount — once a version is published, it must be byte-for-byte IMMUTABLE forever (you can't overwrite v1.2.3), because countless builds pin and depend on that exact version producing the SAME result (reproducible builds), and overwriting would break builds and enable supply-chain attacks; (3) INTEGRITY / SUPPLY-CHAIN SECURITY — downloaders must verify the artifact is exactly what was published (checksums/signing), since registries are prime supply-chain attack targets; and (4) DEPENDENCY metadata — packages declare dependencies, and resolving them requires version/dependency metadata. It's essentially an object store + CDN with strict immutability, integrity, and dependency metadata. So the design centers on immutable artifact storage/serving + metadata/dependency resolution/publishing/security."),
      K("estimation", "Capacity estimation (with numbers)",
        "Reads >> writes: published once, downloaded billions of times -> CDN + cache (read-heavy).\nArtifacts: versioned, IMMUTABLE blobs (tarballs/images) -> object storage (durable, large).\nMetadata: package -> versions + dependencies -> a DB (queried for resolution).\nImmutability: a published version is never overwritten (reproducible builds + security).\nIntegrity: checksums/signatures verify artifacts (supply-chain security).\nTakeaway: immutable versioned artifacts in object storage served via CDN (read-heavy) +\nmetadata DB for versions/dependencies + integrity/immutability + auth on publish."),
      C("hld", "High-level design",
        "PUBLISH: an authenticated publisher uploads a package VERSION — the ARTIFACT (tarball/image blob) is stored in OBJECT STORAGE (immutable, content-addressed or version-keyed), and its METADATA (package name, version, dependencies, checksum, publish info) is written to a metadata DB; the registry computes/records an integrity CHECKSUM (and supports signing) and ENFORCES IMMUTABILITY — a version, once published, can NEVER be overwritten or changed (re-publishing the same version is rejected). DOWNLOAD: installs/builds fetch a package version's artifact — served from a CDN / cache in front of object storage (the read-heavy path: billions of downloads), with the metadata DB providing version/dependency info; downloaders verify the artifact against its checksum (integrity). DEPENDENCY RESOLUTION: a package declares dependencies (with version ranges), and resolving the full dependency tree is done from the METADATA (often CLIENT-SIDE — the package manager fetches metadata and computes the resolution, then downloads the resolved artifacts), since the registry mainly stores + serves. SEARCH/discovery over packages + metadata. SECURITY: auth on publish (only owners publish), integrity verification, signing, and supply-chain protections (malware scanning, vuln advisories). Trace it: publish lib@1.2.3 (auth, checksum, immutable) -> artifact to object store + metadata to DB; install -> resolve deps from metadata -> download artifacts via CDN -> verify checksums. Immutable versioned artifacts (object store) + metadata DB + CDN-served downloads + dependency resolution + integrity is the shape."),
      K("api", "API / flow",
        "publish: auth -> upload version { artifact, metadata, deps } ->\n   store artifact (object storage, IMMUTABLE) + checksum + metadata DB ; reject overwrite of a version\ndownload: GET package@version -> artifact via CDN/cache (read-heavy) ; verify checksum\nmetadata: GET package -> versions + dependencies (for resolution)\nresolve: (often client-side) read metadata -> compute dependency tree -> download resolved artifacts\nsecurity: auth on publish, integrity (checksums/signing), malware/vuln scanning"),
      K("data_model", "Data model",
        "packages: name -> versions list\nversions: (package, version) -> { artifact location, dependencies, checksum, publish info } ; IMMUTABLE\nartifacts: immutable blobs (tarballs/images) in object storage (durable) ; CDN-cached\nmetadata DB: versions + dependency graph (for resolution + search)\nintegrity: checksums/signatures per artifact (supply-chain)"),
      C("deep_dive", "Deep dive: immutable artifact storage & serving",
        "The defining properties are IMMUTABILITY and READ-HEAVY serving. IMMUTABILITY (the crux): once a package version is published, its artifact must be byte-for-byte IMMUTABLE FOREVER — you cannot overwrite or modify v1.2.3. WHY: countless builds PIN exact versions and expect them to produce the SAME result every time (REPRODUCIBLE BUILDS) — if a version's contents could change, a build that worked yesterday could break or behave differently today, and (worse) an attacker who overwrote a popular version with malicious code would compromise everyone who installs it (a supply-chain attack). So the registry ENFORCES immutability: a publish of an already-existing version is REJECTED, and stored artifacts are never mutated (the infamous npm 'unpublish' restrictions exist precisely because removing/changing versions breaks the ecosystem). Artifacts are stored in OBJECT STORAGE (cheap, durable, handles large blobs — tarballs/images), version-keyed or CONTENT-ADDRESSED (keyed by a hash of the content, which inherently guarantees immutability + dedup — the same content has the same address; Docker layers work this way). READ-HEAVY SERVING via CDN: packages are downloaded enormously (every CI build, every developer install — billions of downloads) but each version's content NEVER changes, making it a PERFECT CDN/cache target — serve artifacts from a CDN/edge cache in front of object storage, so the massive download traffic is absorbed at the edge with near-zero origin load and low global latency (immutability means cache-forever, no invalidation). This is the pastebin/object-store + CDN pattern, supercharged by immutability. INTEGRITY: each artifact has a CHECKSUM (and optionally a signature), so downloaders verify the bytes are exactly what was published (tamper detection) — content-addressing makes this intrinsic. So immutable, version-keyed/content-addressed artifacts in object storage, served via CDN (cache-forever due to immutability), with integrity checksums, is the storage/serving core interviewers probe (immutability is THE defining requirement)."),
      C("deep_dive", "Deep dive: metadata, dependency resolution, publishing & security",
        "Beyond storing blobs, the registry manages METADATA, DEPENDENCIES, PUBLISHING, and SECURITY. METADATA: for each package, the registry stores its versions and each version's METADATA — notably its DEPENDENCIES (the other packages + version ranges it needs) — in a metadata DB/service, queried far more flexibly than the blobs. DEPENDENCY RESOLUTION: a package depends on others (often with version RANGES like '^1.2.0'), and installing it requires resolving the full transitive DEPENDENCY TREE to concrete versions (satisfying all version constraints — a constraint-satisfaction problem). Crucially, this resolution is typically done by the CLIENT (the package manager — npm/pip/etc.): it fetches the METADATA (which versions exist, their dependencies) from the registry, computes the resolved set (lockfile), and then downloads the resolved ARTIFACTS — so the registry's job is mainly to serve metadata + artifacts efficiently, while the resolution logic lives client-side (keeping the registry simple + scalable). PUBLISHING flow: AUTHENTICATED (only the package owner/authorized publishers can publish a version — preventing hijacking), validated, integrity-checksummed, and IMMUTABILITY-enforced (no overwriting a version); ownership/permissions management. SECURITY / SUPPLY-CHAIN: registries are PRIME supply-chain attack targets (compromise a popular package -> compromise everyone), so security is paramount: auth on publish, integrity verification (checksums/signatures so installs detect tampering), malware/typosquatting scanning, vulnerability advisories (flag known-vulnerable versions), and provenance/signing (e.g. Sigstore) — protecting the millions of builds that trust the registry. AVAILABILITY: the registry is critical infrastructure (the world's builds depend on it), so it must be highly available (CDN helps — downloads survive even if the origin/metadata has issues, since artifacts are cached + immutable). So metadata-driven (client-side) dependency resolution + authenticated, immutable, integrity-checked publishing + supply-chain security is the metadata/publishing core interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "DOWNLOAD READ SCALE — billions of downloads -> CDN/cache (immutable artifacts = cache-forever, no invalidation) + object storage origin. IMMUTABILITY — must never overwrite a version (reproducible builds + security) -> reject re-publish, content-address/version-key, never mutate. INTEGRITY / SUPPLY-CHAIN — registries are attack targets -> checksums/signing, auth on publish, malware/vuln scanning. METADATA scale — dependency metadata queried for resolution -> a scalable metadata DB; resolution offloaded to clients. STORAGE GROWTH — every version kept forever (immutability) -> cheap object storage, dedup (content-addressing). AVAILABILITY — critical infra -> CDN + replication. Trade-offs: content-addressed storage (intrinsic immutability + dedup + integrity — indirection) vs version-keyed (simpler — must enforce immutability separately); CDN cache-forever (massive offload, low latency — immutability required, which holds) vs origin-served (simple — can't handle the load); client-side resolution (simple/scalable registry, flexible — clients do the work, need full metadata) vs server-side resolution (centralized — registry complexity/load); strict immutability (reproducible + secure — can't fix a bad publish except by a new version) vs mutable (flexible — breaks builds + insecure — unacceptable); keep all versions forever (reproducibility — storage) vs prune (cheaper — breaks pinned builds). Closing signal: immutable, version-keyed/content-addressed artifacts in object storage served via CDN (cache-forever, read-heavy), a metadata DB driving (client-side) dependency resolution, and authenticated, integrity-checked, immutability-enforced publishing with supply-chain security — a read-heavy, immutable, secure artifact registry the world's builds can trust."),
      C("deep_dive", "Deep dive: caching, mirrors, scanning & operations",
        "Operationally a package registry is critical, security-sensitive, read-dominated infrastructure. CDN & caching layers: downloads are served from a CDN (and often regional MIRRORS / proxy caches in CI/enterprises) — immutability means artifacts cache forever (no invalidation), so the origin (object storage) sees only cache misses; this is the main scaling lever and what keeps a global registry affordable + fast. Object storage origin: durable, replicated blob storage for artifacts; content-addressing dedups identical content (e.g. shared Docker layers). Metadata service: serves package/version/dependency metadata (read-heavy too, cached) for resolution + search; a search index for discovery. Publishing pipeline: auth (tokens/2FA for owners), validation, checksum/signature, immutability enforcement, and async post-publish processing (malware/typosquat scanning, vulnerability analysis, generating integrity data). Supply-chain security: signing/provenance (Sigstore, signed artifacts), vulnerability advisories + alerts (flag/yank vulnerable versions — yank = mark unusable without deleting, preserving immutability), 2FA for maintainers, and detecting account takeover / malicious packages (a major real-world threat). Yank vs unpublish: you generally can't delete/overwrite (breaks builds), so 'yank/deprecate' marks a version discouraged while keeping it downloadable for existing pins. Replication/mirrors: regional mirrors + enterprise proxies reduce latency and provide resilience/air-gapped installs. Scale & availability: the registry's downtime stalls the world's CI, so HA is critical — CDN-served immutable artifacts keep installs working even during partial outages. Namespacing/scopes: package namespaces/scopes + ownership/permissions. Stats: download counts/analytics. Observability: download throughput + CDN hit rate, publish success, origin/metadata latency, and security-scan/vuln rates are the SLOs. The spine holds: immutable content-addressed artifacts in object storage + CDN/mirrors (cache-forever), metadata-driven client-side resolution, authenticated immutable integrity-checked publishing, with supply-chain scanning/signing and HA."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Why must versions be immutable?' reproducible builds (a pinned version must always be identical) + security (overwriting a popular version = supply-chain attack); so the registry rejects re-publishing a version and never mutates artifacts. 'Serve billions of downloads?' CDN/cache in front of object storage — and because artifacts are IMMUTABLE, they cache FOREVER (no invalidation), so the origin sees almost no load. 'Storage?' immutable blobs in object storage, often CONTENT-ADDRESSED (hash-keyed) which gives intrinsic immutability + integrity + dedup (shared Docker layers). 'Dependency resolution?' from METADATA (versions + dependency ranges), typically done CLIENT-SIDE (the package manager fetches metadata, computes the resolved tree/lockfile, downloads artifacts) — the registry serves metadata + blobs. 'Security / supply chain?' auth on publish (owners only, 2FA), integrity checksums/signing, malware/typosquat scanning, vulnerability advisories — registries are prime attack targets. 'Fix a bad/vulnerable version?' you can't overwrite (breaks builds) — publish a new version and YANK/deprecate the bad one (still downloadable for existing pins). 'Availability?' critical infra — CDN-served immutable artifacts keep installs working through outages. 'Mirrors?' regional/enterprise proxy caches. Each returns to the spine: immutable content-addressed artifacts in object storage + CDN, metadata-driven client-side resolution, authenticated immutable integrity-checked publishing + supply-chain security."),
    ],
    "A package registry tests IMMUTABLE, versioned artifact storage (content-addressed/version-keyed blobs in object storage that can NEVER be overwritten — for reproducible builds + supply-chain security) served via CDN (cache-forever, absorbing billions of read-heavy downloads), plus a metadata DB driving (client-side) dependency resolution and authenticated, integrity-checked (checksums/signing) publishing with supply-chain scanning. The signal is immutability + CDN-served read-heavy artifacts + metadata-driven resolution + integrity, not a mutable file server.",
    [
      G("mutable_versions", "Allowing a published version to be overwritten/changed.", "Enforce immutability — a version, once published, is never overwritten (reproducible builds + supply-chain security); yank/deprecate instead of overwrite.", "Lets publishers re-upload the same version with new content; breaks pinned builds + enables attacks."),
      G("no_cdn", "Serving billions of downloads directly from the origin/DB.", "Serve artifacts via CDN/cache — immutability means cache-forever (no invalidation), absorbing the read-heavy download load at the edge.", "Downloads hit object storage/origin directly; can't handle install-scale read traffic."),
      G("no_integrity", "Ignoring artifact integrity / publish auth (supply-chain).", "Authenticate publishing (owners, 2FA) + integrity checksums/signing + malware/vuln scanning — registries are prime supply-chain targets.", "No checksums/signing/auth; tampered or hijacked packages go undetected."),
    ],
    0.5, DIAG.packagereg, "Package registry architecture"),

  // ──────────────────── CAPTCHA / BOT DETECTION SERVICE ─────────────────────
  TT("sysd_m19", "sysd_m19_t6", 6, "Design a Captcha / Bot Detection Service", "design-bot-detection",
    ["case-study", "bot-detection", "risk-scoring", "adversarial"],
    "Bots scrape your content, stuff stolen credentials, and create fake accounts by the million — but slapping a CAPTCHA on every request would drive away the humans you're protecting. How do you tell bots from humans, block the bots, and keep real users almost entirely un-bothered?",
    "Score each request on many PASSIVE signals (behavioral patterns, device fingerprint, IP reputation, request rate) with an ML model — invisibly for the vast majority — and present a CHALLENGE (CAPTCHA / proof-of-work) only to SUSPICIOUS (risk-based) traffic, minimizing friction for humans. Adapt continuously as bots evolve (adversarial → retrain) and rate-limit. It mirrors fraud detection: risk scoring + selective challenge + feedback. Multi-signal risk scoring + challenges/adversarial-adaptation/friction-balance are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: distinguish BOTS from HUMANS and block/challenge automated abuse — scraping, credential stuffing, fake-account creation, spam, scalping; allow legitimate users through; provide a CHALLENGE (CAPTCHA) when needed. Non-functional: LOW FRICTION for real humans (don't make everyone solve puzzles — that hurts UX/conversion), ADAPTABILITY (bots constantly evolve — adversarial), low LATENCY (the decision is on the request path), and high accuracy (block bots, don't block humans). Clarify scope: a bot-detection / CAPTCHA service (Cloudflare-bot-management / reCAPTCHA style). The defining challenges closely mirror FRAUD DETECTION: (1) it's ADVERSARIAL — attackers continuously evolve their bots to evade detection, so a static rule/model decays and the system must keep ADAPTING (retraining on new bot behavior); (2) the FRICTION trade-off — you protect users by detecting bots, but heavy-handed detection (CAPTCHA on everyone) drives away the very HUMANS you're protecting (a CAPTCHA is friction/abandonment), so you must catch bots while keeping the experience nearly INVISIBLE for legitimate users — meaning you can't just challenge everyone; and (3) DETECTION accuracy from limited signals at request time. The modern approach is RISK-BASED / multi-signal: score each request invisibly using many passive signals, let the obvious-human majority pass with NO challenge, and only CHALLENGE (CAPTCHA) the suspicious minority. So the design centers on multi-signal risk scoring (mostly invisible) + selective challenges + adversarial adaptation, balancing security against human friction."),
      K("estimation", "Capacity estimation (with numbers)",
        "Volume: huge request rate -> low-latency scoring on the request path (ms).\nSignals: passive -> behavior (mouse/timing), device fingerprint, IP reputation, request rate/patterns.\nDecision: ML risk score -> low risk = allow (invisible) ; high/uncertain = CHALLENGE (CAPTCHA).\n  -> minimize challenges shown to humans (friction) while blocking bots.\nAdaptation: bots evolve -> feedback (caught bots) -> retrain (adversarial).\nTakeaway: multi-signal ML risk scoring (mostly invisible) + selective challenge for suspicious\n+ continuous adaptation -> block bots with minimal human friction (mirrors fraud detection)."),
      C("hld", "High-level design",
        "Each request is SCORED for bot-likelihood using MANY PASSIVE signals — BEHAVIORAL (mouse movement, typing cadence, interaction patterns — humans move differently than scripts), DEVICE FINGERPRINT (browser/device characteristics, headless-browser tells), IP/network REPUTATION (known bot/datacenter/proxy IPs, ASN), and REQUEST PATTERNS (rate, timing, sequence) — fed to an ML model that outputs a RISK score, mostly INVISIBLY (no user interaction). Based on the score: LOW risk -> ALLOW silently (the human majority sails through, no friction); HIGH/uncertain risk -> present a CHALLENGE — a CAPTCHA (image/checkbox), an invisible proof-of-work, or step-up — that's easy for humans but hard for bots, so legitimate users pass and bots fail/are deterred (RISK-BASED challenging minimizes friction by challenging only the suspicious). RATE LIMITING throttles abusive patterns. ADAPTATION: caught bots and outcomes FEED BACK to RETRAIN the models continuously, because bots evolve to evade (adversarial arms race). This is structurally the FRAUD-DETECTION pattern (real-time multi-signal risk scoring + a challenge tier + feedback/retraining). Trace it: request -> collect passive signals -> ML risk score -> low: allow (invisible); high: show CAPTCHA -> human solves (allowed) / bot fails (blocked); caught bots -> retrain. Multi-signal ML risk scoring (mostly invisible) + selective challenge for suspicious + feedback/adaptation is the shape.",),
      K("api", "API / flow",
        "request -> collect passive signals (behavior, device fingerprint, IP reputation, rate/patterns)\nscore: ML risk model -> bot-likelihood score\n  LOW  -> allow silently (invisible, no friction)\n  HIGH/uncertain -> CHALLENGE (CAPTCHA / invisible proof-of-work / step-up)\n  obvious bot -> block / rate-limit\nfeedback: caught bots + outcomes -> retrain models (adversarial adaptation)\nrate limiting: throttle abusive patterns/IPs"),
      K("data_model", "Data model",
        "signals: behavioral + device fingerprint + IP/network reputation + request patterns\nrisk model: ML scorer (bot-likelihood) + thresholds (allow / challenge / block)\nchallenges: CAPTCHA / proof-of-work / step-up (for suspicious only)\nreputation: IP/device/account reputation stores\nfeedback/labels: caught bots, challenge outcomes -> retraining data"),
      C("deep_dive", "Deep dive: multi-signal risk scoring (mostly invisible)",
        "The core is scoring bot-likelihood from MANY signals so MOST users are judged INVISIBLY. The naive approach — show everyone a CAPTCHA — works to block bots but inflicts FRICTION on all humans (abandonment, bad UX), which is unacceptable; modern bot detection therefore decides RISK passively first and only challenges the suspicious. SIGNALS (collected without bothering the user): BEHAVIORAL — how the client interacts (mouse trajectories, scroll, typing rhythm, touch — humans exhibit natural, variable motion; scripts are robotic or absent), and timing/navigation patterns; DEVICE/BROWSER FINGERPRINT — characteristics of the browser/device (and tells of automation/headless browsers, inconsistent fingerprints, missing capabilities); IP / NETWORK REPUTATION — is the IP a known bot source, datacenter/cloud IP (humans are usually on residential/mobile), proxy/VPN, or on a blocklist; and REQUEST PATTERNS — rate, regularity, sequences (a human browses irregularly; a scraper hits endpoints fast/systematically). An ML MODEL combines these into a RISK score (bots cluster in feature space). DECISION: most requests score clearly HUMAN -> ALLOWED with NO interaction (invisible — the key to low friction); clearly BOT -> blocked/throttled; UNCERTAIN/suspicious -> escalated to a CHALLENGE. This RISK-BASED approach (invisible scoring + challenge only the uncertain) is exactly the fraud-detection allow/deny/challenge model applied to bots, and is what lets you protect against bots while keeping the experience seamless for the human majority. It's all on the request path, so scoring must be LOW-LATENCY (fast feature lookup + model). So multi-signal passive risk scoring (behavior + fingerprint + IP reputation + patterns) that's invisible for most users, reserving challenges for the suspicious, is the detection core interviewers probe (the wrong instinct is 'CAPTCHA everyone')."),
      C("deep_dive", "Deep dive: challenges, adversarial adaptation & the friction trade-off",
        "The other pillars are the CHALLENGE mechanism, ADVERSARIAL adaptation, and the FRICTION balance. CHALLENGES (for suspicious traffic only): when a request is risky/uncertain, present a CHALLENGE that's EASY for humans but HARD for bots — a CAPTCHA (distorted text, image selection, a simple checkbox backed by behavioral analysis), an INVISIBLE proof-of-work (make the client do computation — cheap for one user, expensive at bot scale), or a step-up (verify via another factor) — so a legitimate user passes (proving humanity) while a bot fails or finds it too costly at scale. Reserving challenges for the suspicious MINIMIZES the friction inflicted on humans (most never see one). The ARMS RACE / ADVERSARIAL ADAPTATION: this is fundamentally adversarial — attackers constantly EVOLVE (better headless browsers, residential proxies, CAPTCHA-solving farms/AI, mimicking human behavior) to evade detection, so any static model DECAYS; the system must continuously ADAPT — FEED BACK caught bots and outcomes as LABELS to RETRAIN models, update signals/reputation, and react to new attack patterns (like fraud detection's feedback loop), an ongoing battle with no permanent win. The FRICTION TRADE-OFF is the central design tension: more aggressive detection/challenging catches more bots but creates more FALSE POSITIVES (challenging/blocking real humans — friction, abandonment, lost users), while lenient detection lets bots through; you tune the risk thresholds and challenge logic to balance security against human experience (and CAPTCHAs themselves are a friction + accessibility cost). RATE LIMITING complements scoring (throttle abusive volume regardless of classification). So selective (risk-based) challenges + continuous adversarial retraining + carefully balancing detection strength against human friction (false positives) is the operational core interviewers probe (it's the same shape as fraud detection's challenge + feedback + precision/recall trade-off)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "FALSE POSITIVES (human friction) — challenging/blocking real users hurts UX/conversion -> risk-based challenges (only the suspicious), tuned thresholds, invisible scoring for the majority. ADVERSARIAL EVOLUTION — bots constantly evade -> continuous feedback + retraining, updated signals/reputation (an arms race, never 'done'). LATENCY — scoring is on the request path -> fast multi-signal model. BOT SOPHISTICATION — headless browsers, residential proxies, CAPTCHA farms/AI solvers -> layered signals + proof-of-work (cost) + behavioral analysis. ACCESSIBILITY — CAPTCHAs exclude some users -> invisible/behavioral challenges, alternatives. Trade-offs: risk-based invisible scoring + selective challenge (low human friction, catches most — needs good signals/ML) vs CAPTCHA-everyone (simple, blocks bots — terrible human UX) vs no detection (frictionless — overrun by bots); aggressive thresholds (catch more bots — more false positives/friction) vs lenient (less friction — more bots through); behavioral/invisible challenges (low friction, accessible — bots improving at mimicry) vs hard CAPTCHAs (harder for bots — friction + accessibility cost); proof-of-work (scales cost to bots — minor user compute) vs CAPTCHA (human-verifying — friction); continuous retraining (adapts — ops cost) vs static (cheap — decays). Closing signal: multi-signal ML risk scoring (behavior + device fingerprint + IP reputation + patterns) that judges most users INVISIBLY, reserving CHALLENGES (CAPTCHA / proof-of-work) for SUSPICIOUS traffic to minimize human friction, with rate limiting and continuous feedback-driven RETRAINING against evolving bots — protecting against automation while keeping legitimate users nearly un-bothered (the fraud-detection pattern for bots)."),
      C("deep_dive", "Deep dive: reputation, proof-of-work, privacy & operations",
        "Operationally bot detection is an adversarial, latency-sensitive, privacy-sensitive service. Reputation systems: IP/ASN reputation (datacenter vs residential, known-bad), device/browser reputation, and account reputation feed scoring; shared threat intelligence across customers (a network effect — Cloudflare sees bots across millions of sites) makes detection stronger. Layered defenses: passive scoring + JS challenges (run code only a real browser executes) + behavioral biometrics + proof-of-work + CAPTCHA, escalating by risk; defense-in-depth since any single signal is evadable. Proof-of-work: invisible computational challenges that are cheap for one legit client but expensive at bot scale (raising the attacker's cost) — increasingly used over visible CAPTCHAs. CAPTCHA evolution: from distorted text -> image selection -> invisible/behavioral (reCAPTCHA v3 risk score) -> privacy-preserving attestation (Privacy Pass / device attestation) to reduce friction; accessibility alternatives matter. Privacy: collecting fingerprints/behavior raises privacy concerns + regulation -> privacy-preserving approaches (attestation tokens proving humanity without tracking). Feedback & MLOps: caught bots, challenge solve rates, and honeypots generate labels; retrain models, monitor drift, and respond to new attack campaigns (like fraud MLOps). Use-case tuning: thresholds per action (login/credential-stuffing, signup/fake-accounts, scraping, checkout/scalping) — different risk tolerance and friction budgets. Rate limiting & WAF integration: complements classification (the WAF/DDoS/rate-limiter designs) — bot management often sits in the edge/WAF layer. Honeypots/traps: hidden links/fields that only bots hit, generating labels + blocks. Bot 'good vs bad': allow good bots (search crawlers) via verification, block bad ones. Observability: bot-block rate, human challenge rate (friction), false-positive rate, solve rates, and detection latency are the SLOs. The spine holds: multi-signal risk scoring (+ shared reputation/threat intel) -> invisible-allow / risk-based-challenge (CAPTCHA/PoW) / block, with rate limiting, continuous adversarial retraining, and privacy-aware challenges."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Why not CAPTCHA everyone?' it blocks bots but inflicts friction on all humans (abandonment) — instead score RISK invisibly from passive signals and challenge only the SUSPICIOUS minority. 'What signals?' behavioral (mouse/timing — humans vs scripts), device/browser fingerprint (headless tells), IP/network reputation (datacenter vs residential, blocklists), and request patterns (rate/regularity) — combined by an ML model. 'Challenge?' for risky/uncertain requests only — CAPTCHA, invisible proof-of-work (cheap per human, costly at bot scale), or step-up — easy for humans, hard/expensive for bots. 'Bots keep evolving?' it's adversarial — feed caught bots back as labels and RETRAIN continuously, update signals/reputation (an arms race, never finished). 'Friction trade-off?' more aggressive = more bots caught but more false positives (frustrated humans) — tune thresholds to balance security vs UX. 'Sophisticated bots (residential proxies, CAPTCHA farms, AI solvers)?' layered signals + proof-of-work (cost) + behavioral analysis + shared threat intel. 'Relation to fraud detection?' same pattern — real-time multi-signal risk scoring + a challenge tier + feedback/retraining. 'Privacy?' privacy-preserving attestation (prove humanity without tracking). 'Good bots?' allow verified crawlers. Each returns to the spine: multi-signal invisible risk scoring + risk-based challenges + continuous adversarial retraining, balancing security vs human friction."),
    ],
    "A bot-detection/CAPTCHA service tests RISK-BASED, multi-signal scoring (behavior + device fingerprint + IP reputation + request patterns via ML) that judges most users INVISIBLY and reserves CHALLENGES (CAPTCHA / proof-of-work) for SUSPICIOUS traffic to minimize human FRICTION, with rate limiting and continuous FEEDBACK-driven retraining against ADVERSARIAL, evolving bots — structurally the fraud-detection pattern (risk scoring + selective challenge + adaptation). The signal is invisible multi-signal risk scoring + selective challenge + adversarial adaptation/friction-balance, not 'show everyone a CAPTCHA'.",
    [
      G("captcha_everyone", "Challenging every user with a CAPTCHA.", "Score risk invisibly from passive signals; challenge only suspicious traffic (risk-based) to minimize friction for the human majority.", "Puts a CAPTCHA on every request/login; high human friction + abandonment."),
      G("static_detection", "A static rule/model with no adaptation.", "Bots are adversarial — feed caught bots back as labels and retrain continuously; update signals/reputation (arms race).", "One-time rules/model; bots evolve and evade; detection decays."),
      G("single_signal", "Relying on one signal (e.g. IP blocklist) only.", "Combine many signals (behavior + device fingerprint + IP reputation + patterns) — any single signal is easily evaded.", "Blocks only by IP/user-agent; sophisticated bots bypass trivially."),
    ],
    0.6, DIAG.botdetect, "Bot detection / CAPTCHA architecture"),

  // ─────────────────────── STOCK MARKET DATA FEED ──────────────────────────
  TT("sysd_m20", "sysd_m20_t4", 4, "Design a Stock Market Data Feed", "design-market-data-feed",
    ["case-study", "market-data", "low-latency", "fan-out"],
    "An exchange produces a torrent of price quotes and trades, and millions of traders, algos, and apps must all receive each update with microsecond latency and — for fairness — at essentially the same instant. How do you distribute a real-time market data feed at that throughput and fairness?",
    "Ingest the exchange's market events (quotes/trades/order-book updates), SEQUENCE them, and FAN OUT to many subscribers in real time with ultra-low latency — often via MULTICAST so every subscriber receives the same data SIMULTANEOUSLY (fairness) and efficiently; handle massive THROUGHPUT, CONFLATION for slow consumers, and GAP RECOVERY via sequence numbers. Low-latency fair fan-out + throughput/conflation/reliability are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: distribute real-time MARKET DATA — price QUOTES (bid/ask), TRADES, and ORDER BOOK updates — from exchanges to many SUBSCRIBERS (traders, algos, apps, displays); subscribe to symbols. Non-functional: ULTRA-LOW LATENCY (market data is latency-critical — microseconds matter for trading), MASSIVE THROUGHPUT (a huge rate of updates, especially during volatility), FAIRNESS (subscribers should receive the same data at essentially the SAME time — no one unfairly first), ORDERING/correctness (updates in sequence, no loss), and SCALE (many subscribers). Clarify scope: a market-data distribution feed (the dissemination side, downstream of the exchange's matching engine). The defining challenges: (1) ULTRA-LOW-LATENCY, high-THROUGHPUT FAN-OUT — one stream of market events must reach MANY subscribers in microseconds, at an enormous message rate; (2) FAIRNESS — in trading, getting data even microseconds before others is an advantage, so the feed should deliver to all subscribers SIMULTANEOUSLY/equally (a fairness requirement unusual to other systems), which strongly motivates MULTICAST (the network delivers one packet to all subscribers at once) over unicasting to each; and (3) handling SLOW CONSUMERS and RELIABILITY at this rate — a consumer that can't keep up needs CONFLATION (collapse stale updates), and lost packets need GAP RECOVERY (sequence numbers + retransmission). So the design centers on ultra-low-latency fair fan-out (multicast) + throughput/conflation/gap-recovery/ordering."),
      K("estimation", "Capacity estimation (with numbers)",
        "Throughput: huge update rate (millions of messages/sec at peak volatility) per feed.\nLatency: microseconds end-to-end -> efficient encoding, kernel bypass, colocation.\nFan-out: 1 stream -> many subscribers ; fairness = deliver simultaneously -> MULTICAST.\n  (unicast to N subscribers = N copies + staggered delivery = unfair + costly).\nSlow consumers: can't keep up -> CONFLATION (drop stale, send latest).\nReliability: sequence numbers -> detect gaps -> retransmission/recovery.\nTakeaway: ultra-low-latency multicast fan-out (simultaneous/fair) + sequencing + conflation\nfor slow consumers + gap recovery -> high-throughput fair real-time market data."),
      C("hld", "High-level design",
        "INGEST: market EVENTS (quotes, trades, order-book updates) flow from the exchange (the matching engine's market-data output) into the feed; they are SEQUENCED (assigned monotonic SEQUENCE NUMBERS) so subscribers can order them and detect loss. FAN-OUT: the feed distributes each update to MANY SUBSCRIBERS in real time with ultra-low latency — typically via MULTICAST: the network delivers a single published packet to ALL subscribers at once, so everyone gets the SAME data SIMULTANEOUSLY (fairness — no subscriber is systematically first) and efficiently (one send reaches all, vs unicasting N copies); subscribers join the multicast group(s) for the symbols they want. The encoding is compact/binary and the path is optimized for microseconds (kernel-bypass networking, colocation near the exchange). SLOW CONSUMERS: a subscriber that can't keep up with the firehose would fall behind, so CONFLATION collapses updates — for a fast-changing quote, send only the LATEST value rather than every intermediate tick (the subscriber gets current state, not a backlog). RELIABILITY / GAP RECOVERY: since multicast (often UDP-based) can drop packets, each message carries a SEQUENCE NUMBER so a subscriber DETECTS a gap (missing sequence) and requests RETRANSMISSION (or reads from a recovery/snapshot channel) — guaranteeing eventual completeness without slowing the fast path. Trace it: exchange event -> sequenced -> multicast to all subscribers (simultaneous) -> subscriber applies in order; a slow consumer gets conflated latest values; a dropped packet (gap in sequence) -> request retransmit. Ingest+sequence -> ultra-low-latency multicast fan-out (fair/simultaneous) + conflation + gap recovery is the shape."),
      K("api", "API / flow",
        "ingest: exchange market events (quotes/trades/order book) -> SEQUENCE (monotonic numbers)\nfan-out: MULTICAST published updates -> all subscribers SIMULTANEOUSLY (fair, efficient)\n  subscribers join multicast group(s) per symbol ; compact binary encoding ; microsecond path\nslow consumer: CONFLATION -> send latest value, drop stale intermediates\nreliability: sequence numbers -> detect gap -> retransmission / snapshot recovery channel\nordering: subscribers order by sequence number"),
      K("data_model", "Data model",
        "market events: quotes (bid/ask), trades, order-book updates -> sequenced (monotonic seq #)\nmulticast groups: per symbol/feed -> subscribers join\nsubscribers: which symbols/feeds (multicast group membership)\nrecovery: sequence numbers + retransmission/snapshot channel (gap recovery)\nconflation state: latest value per symbol (for slow consumers)"),
      C("deep_dive", "Deep dive: ultra-low-latency, fair fan-out (multicast)",
        "The defining engineering is delivering market data to MANY subscribers with microsecond latency AND fairness — which strongly motivates MULTICAST. FAIRNESS — the unusual requirement: in trading, receiving a price update even microseconds before others is a real ADVANTAGE, so the feed must deliver to all subscribers as SIMULTANEOUSLY and equally as possible — you can't unicast to subscriber A then B then C (the later ones get it microseconds later — systematically unfair) and you can't have some subscribers privileged. MULTICAST solves both fairness and efficiency: the publisher sends ONE packet and the NETWORK fans it out to ALL subscribers in the multicast group essentially at the same instant — so everyone receives the same data simultaneously (fair) and the publisher does one send regardless of subscriber count (efficient — unicasting to thousands of subscribers would be N copies + staggered + bandwidth-heavy). Subscribers JOIN multicast groups for the symbols/feeds they want. ULTRA-LOW LATENCY: every microsecond counts, so the path is heavily optimized — COMPACT BINARY encoding (minimal parse/serialize), KERNEL-BYPASS networking (e.g. user-space networking to avoid OS overhead), COLOCATION (subscribers' servers physically near the exchange/feed to cut propagation delay), and minimal processing on the hot path; latency fairness also drives equal cable lengths/colocation. ORDERING via SEQUENCE NUMBERS: each message is stamped with a monotonic sequence so subscribers process updates in the correct ORDER and can detect loss. This multicast-based, microsecond-optimized, simultaneous-delivery fan-out (fairness + efficiency + ordering) is the core that distinguishes a market-data feed from a normal pub/sub system — and exactly what interviewers probe (unicast-per-subscriber is the wrong instinct)."),
      C("deep_dive", "Deep dive: throughput, conflation & reliability (gap recovery)",
        "The other pillars are sustaining huge THROUGHPUT, handling SLOW consumers, and RELIABILITY at speed. THROUGHPUT: market data is a FIREHOSE — millions of messages/sec at peak (volatility, market open) — so the entire pipeline (ingest, sequence, encode, multicast) must sustain that rate with minimal per-message overhead (compact binary, batching where it doesn't add latency, efficient I/O); the feed is bandwidth- and processing-intensive. CONFLATION (for slow consumers): not every subscriber can process the full firehose (a UI displaying a price, a slower app), and a subscriber that falls behind would accumulate an ever-growing backlog of STALE updates — so CONFLATION collapses updates: for a frequently-changing value (a quote ticking many times/sec), send only the LATEST value rather than every intermediate tick, so a slow consumer always gets CURRENT state without drowning in history (it doesn't care about superseded quotes). Different consumers get different feed tiers (full tick-by-tick for HFT, conflated for displays). Conflation trades completeness for keeping slow consumers current. RELIABILITY / GAP RECOVERY: multicast is typically UDP-based (for low latency — no per-receiver acks/retransmission on the fast path), which can DROP packets, so the feed provides recovery WITHOUT slowing the fast path: each message has a SEQUENCE NUMBER, a subscriber DETECTS a GAP (a missing sequence number) and then requests RETRANSMISSION of the missed messages (from a retransmission service) or re-syncs from a periodic SNAPSHOT / refresh channel (especially for order-book state — apply a snapshot + subsequent incremental updates) — so subscribers eventually have complete, correct data despite occasional loss, while the primary path stays minimal-latency. ORDERING is maintained via the sequence numbers. So sustaining firehose throughput + conflation for slow consumers + sequence-number-based gap recovery (retransmission/snapshots) is the operational core interviewers probe (it's how a low-latency lossy multicast feed stays correct and usable)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "LATENCY (microseconds) is paramount -> multicast + compact binary + kernel-bypass + colocation; any overhead is costly. FAN-OUT to many subscribers fairly -> multicast (one send, simultaneous) not unicast (N copies, staggered, unfair). THROUGHPUT (firehose) -> efficient pipeline, minimal per-message cost. SLOW CONSUMERS -> conflation (send latest, drop stale) so they stay current without backlog. RELIABILITY at speed -> sequence numbers + gap detection + retransmission/snapshot recovery (don't slow the fast path with acks). FAIRNESS -> simultaneous delivery (multicast), equal latency (colocation). Trade-offs: multicast (simultaneous/fair, efficient one-send — UDP/lossy, needs gap recovery, network must support it) vs unicast per subscriber (reliable/simple — staggered/unfair + N copies + bandwidth); UDP multicast (low latency — packet loss -> recovery needed) vs TCP (reliable — too slow/per-receiver); conflation (slow consumers stay current, lower bandwidth — loses intermediate ticks) vs full tick-by-tick (complete — overwhelms slow consumers); sequence + retransmit recovery (complete data, fast primary path — recovery complexity) vs ack-everything (reliable — kills latency); snapshot+incremental (recover order-book state — snapshot overhead) vs full-resend. Closing signal: ingest + SEQUENCE market events, then ULTRA-LOW-LATENCY MULTICAST fan-out delivering to all subscribers SIMULTANEOUSLY (fairness + efficiency), with compact binary encoding/kernel-bypass/colocation for microseconds, CONFLATION for slow consumers, and sequence-number gap detection + retransmission/snapshot recovery for reliability — a fair, high-throughput, microsecond real-time market data feed."),
      C("deep_dive", "Deep dive: order-book feeds, normalization, tiers & operations",
        "Operationally a market-data system spans ingestion from many sources to diverse consumers. Feed types & order book: feeds range from top-of-book (best bid/ask) to FULL order-book DEPTH (every level) and trade prints; order-book feeds send a SNAPSHOT + a stream of INCREMENTAL updates (apply increments to the snapshot to maintain the book) — gap recovery re-snapshots if a subscriber loses sync. Normalization: ingest from MANY exchanges/venues, each with its own protocol/format, and NORMALIZE into a common format (a normalized/consolidated feed) — a real engineering effort; consolidated feeds (e.g. SIP) aggregate across venues. Tiers & latency: direct exchange feeds + colocation for the lowest latency (HFT), vs slower/conflated/consolidated feeds for less latency-sensitive consumers (apps, retail) — different products at different latency/cost. Sequencing & A/B feeds: exchanges often send two redundant feed lines (A and B); subscribers arbitrate between them (use whichever packet arrives first / fill gaps from the other) for reliability without retransmission latency. Recovery infrastructure: a retransmission server + periodic snapshot channel for subscribers that fall behind or join mid-stream. Distribution architecture: edge/regional distribution (relay multicast across regions where native multicast isn't available — e.g. over WAN via unicast relays then re-multicast), since internet multicast is limited (multicast works in controlled networks/data centers). Capacity for bursts: peak rates (open/close, news) far exceed average -> headroom + backpressure/conflation. Timestamps/clocks: precise, synchronized timestamps on events (for sequencing + latency measurement + regulatory). Monitoring: latency (and latency fairness across subscribers), message rates, gap/retransmission rates, and slow-consumer/conflation metrics are the SLOs. Cost: bandwidth + colocation are significant. The spine holds: normalized ingest + sequencing + ultra-low-latency multicast (A/B redundancy) + conflation tiers + snapshot/retransmission recovery, with colocation and per-venue normalization."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you fan out to many subscribers fairly + fast?' MULTICAST — one published packet the network delivers to ALL subscribers SIMULTANEOUSLY (fairness — no one systematically first) and efficiently (one send, not N unicast copies); subscribers join groups per symbol. 'Microsecond latency?' compact binary encoding + kernel-bypass networking + colocation near the exchange + minimal hot-path processing. 'Slow consumers can't keep up?' CONFLATION — send the latest value and drop superseded intermediate ticks, so they stay current without a growing backlog (full tick-by-tick for HFT, conflated for displays). 'Multicast/UDP drops packets — reliability?' sequence numbers let subscribers DETECT gaps and request RETRANSMISSION, or re-sync from a periodic SNAPSHOT channel (esp. order-book state = snapshot + incrementals) — without slowing the fast path with acks. 'Throughput?' the pipeline sustains millions of msgs/sec (efficient encoding, headroom for bursts at open/close/news). 'Order book?' snapshot + incremental updates applied in sequence. 'Many exchanges?' normalize each venue's protocol into a common format (consolidated feed). 'Redundancy?' A/B feed lines arbitrated by the subscriber. 'Why not TCP?' per-receiver reliability/acks add latency + don't scale the fan-out; UDP multicast + recovery is the low-latency answer. Each returns to the spine: sequence + ultra-low-latency multicast (fair/simultaneous) + conflation + gap recovery."),
    ],
    "A stock market data feed tests ultra-low-latency, FAIR fan-out — MULTICAST so all subscribers receive each sequenced update SIMULTANEOUSLY (fairness, since microseconds are an edge) and efficiently (one send, not N unicasts), with compact binary encoding/kernel-bypass/colocation for microseconds — plus sustaining firehose THROUGHPUT, CONFLATION for slow consumers (send latest, drop stale), and sequence-number GAP RECOVERY (retransmission/snapshots) for reliability over lossy UDP. The signal is multicast fair simultaneous fan-out + conflation + gap recovery, not unicast-per-subscriber pub/sub.",
    [
      G("unicast_fanout", "Unicasting the feed separately to each subscriber.", "Use multicast — one send the network delivers to all subscribers simultaneously (fair + efficient); unicast is staggered (unfair) + N copies.", "Sends a separate copy to each subscriber; staggered delivery (unfair) and bandwidth blowup."),
      G("no_conflation", "Sending the full firehose to every consumer regardless of speed.", "Conflate for slow consumers — send the latest value and drop superseded ticks so they stay current without a backlog.", "A slow consumer accumulates an ever-growing backlog of stale updates."),
      G("no_gap_recovery", "Ignoring packet loss on a low-latency UDP/multicast feed.", "Sequence-number every message so subscribers detect gaps and request retransmission / re-sync from snapshots — without slowing the fast path.", "No sequence numbers/recovery; dropped packets leave subscribers with silently wrong data."),
    ],
    0.7, DIAG.marketdata, "Stock market data feed architecture"),

  // ─────────────────────── LAST-MILE DELIVERY ROUTING ──────────────────────
  TT("sysd_m20", "sysd_m20_t5", 5, "Design Last-Mile Delivery Routing", "design-last-mile-routing",
    ["case-study", "routing", "optimization", "real-time"],
    "A courier has 30 packages to drop across a city in one shift; you must choose which packages go to which courier and the order of stops to minimize driving — then re-plan on the fly as new orders arrive and traffic shifts, while customers watch the van approach in real time. How do you build last-mile delivery routing?",
    "ASSIGN deliveries to couriers (by location/capacity/constraints), then compute an efficient multi-stop ROUTE per courier — a vehicle-routing/TSP-like OPTIMIZATION solved with heuristics (exact is NP-hard) — and provide real-time TRACKING (live courier location), ETAs (via maps/routing), and DYNAMIC RE-OPTIMIZATION as new orders/traffic arrive. It combines geo + optimization + live tracking. Assignment + route optimization, plus real-time tracking/ETAs/re-optimization, are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: take DELIVERIES (orders with pickup/dropoff locations, time windows), ASSIGN them to COURIERS, compute efficient multi-stop ROUTES (the order to visit stops), navigate couriers, provide real-time TRACKING + ETAs to customers, and RE-PLAN as conditions change (new orders, traffic, cancellations). Non-functional: ROUTE OPTIMIZATION quality (minimize distance/time/cost — efficiency drives margins), REAL-TIME updates (tracking, dynamic re-routing), SCALE (many couriers + deliveries across cities), and responsiveness. Clarify scope: last-mile delivery routing (the final leg — depot/store to customer; food delivery, parcels, courier logistics). It COMBINES several patterns: GEO (locations, the maps/proximity designs), OPTIMIZATION (the routing math), and LIVE TRACKING (the live-location design). The defining challenges: (1) ROUTE OPTIMIZATION — given a courier with many stops, find the ORDER to visit them minimizing travel (the Traveling Salesman Problem), and given many couriers + deliveries, decide WHICH deliveries go to WHICH courier and their routes (the Vehicle Routing Problem) — both NP-HARD, so solved with HEURISTICS/approximations at scale; and (2) DYNAMIC / real-time RE-OPTIMIZATION — it's not a one-shot plan: new orders arrive, traffic changes, deliveries fail — so routes must be continuously RE-OPTIMIZED, plus real-time tracking + ETAs for customers. So the design centers on assignment + multi-stop route optimization (heuristic VRP/TSP) + real-time tracking/ETAs/dynamic re-optimization."),
      K("estimation", "Capacity estimation (with numbers)",
        "Scale: many couriers * many deliveries per shift, across cities -> distribute by region.\nRouting: per courier, order N stops to minimize travel (TSP) ; assign deliveries to couriers (VRP).\n  -> NP-hard -> heuristics/approximation (not exact optimal at scale).\nDynamic: new orders + traffic + failures -> RE-OPTIMIZE routes continuously.\nTracking: live courier location (throttled) -> customer sees ETA (live-location pattern).\nETA: via a maps/routing engine (road network + traffic).\nTakeaway: assign deliveries to couriers + optimize multi-stop routes (heuristic VRP/TSP) +\nlive tracking + ETAs + dynamic re-optimization on changes."),
      C("hld", "High-level design",
        "ORDERS (deliveries with locations + time windows) are ASSIGNED to COURIERS — matching deliveries to the right courier by location (nearby), capacity (vehicle/load), and constraints (time windows, skills) — often BATCHING nearby deliveries onto one courier for efficiency. For each courier, a ROUTE OPTIMIZER computes the efficient ORDER of stops (a multi-stop route minimizing travel time/distance) — this is a TSP (single courier ordering stops) / VRP (assignment + routing across couriers) problem, solved with HEURISTICS (nearest-neighbor, savings, local search, metaheuristics) since exact optimization is NP-hard and must run fast at scale. A MAPS/ROUTING engine (road network + live traffic — the maps design) provides travel times for optimization, navigation, and ETAs. REAL-TIME TRACKING: couriers stream their location (throttled, the live-location pattern), so customers SEE the courier approaching and an updated ETA. DYNAMIC RE-OPTIMIZATION: because conditions change continuously — NEW orders arrive (assign + insert into a route), TRAFFIC shifts, deliveries fail/are added — the system RE-OPTIMIZES (re-assign / re-sequence) on the fly rather than using a static plan; ETAs update accordingly. Trace it: orders come in -> assign to couriers (location/capacity, batch nearby) -> optimize each courier's stop order (heuristic) -> courier navigates (maps) -> customer tracks live + sees ETA -> a new urgent order arrives -> re-optimize (insert/reassign). Assignment + multi-stop route optimization (heuristic) + live tracking/ETAs + dynamic re-optimization is the shape."),
      K("api", "API / flow",
        "orders: deliveries (pickup/dropoff, time windows) -> queue\nassign: match deliveries -> couriers (location, capacity, constraints) ; batch nearby (VRP)\nroute: optimize stop ORDER per courier (TSP heuristic: nearest-neighbor/savings/local-search)\nnavigate: maps/routing engine (road network + traffic) -> turn-by-turn + travel times\ntrack: courier streams live location (throttled) -> customer ETA (live-location pattern)\nre-optimize: new orders/traffic/failures -> re-assign / re-sequence dynamically + update ETAs"),
      K("data_model", "Data model",
        "deliveries: pickup/dropoff locations, time windows, status\ncouriers: location, capacity, current route (assigned stops in order)\nroutes: ordered list of stops per courier (optimized) ; re-optimized on changes\nmaps/routing: road network + traffic -> travel times, navigation, ETAs\ntracking: live courier location (throttled) -> customer ETA"),
      C("deep_dive", "Deep dive: assignment & route optimization (VRP/TSP heuristics)",
        "The algorithmic core is ASSIGNING deliveries to couriers and ORDERING each courier's stops efficiently — a hard optimization problem. THE PROBLEMS: (a) for ONE courier with N stops, find the ORDER to visit them that minimizes total travel — the TRAVELING SALESMAN PROBLEM (TSP); (b) across MANY couriers and deliveries, decide WHICH deliveries each courier handles AND their routes (respecting vehicle CAPACITY, delivery TIME WINDOWS, courier locations/shifts) — the VEHICLE ROUTING PROBLEM (VRP, a generalization of TSP). Both are NP-HARD — the number of possible routes/assignments explodes combinatorially, so finding the EXACT optimal is infeasible at real scale (dozens of stops, many couriers, real-time). So real systems use HEURISTICS and APPROXIMATION ALGORITHMS that find GOOD (near-optimal) solutions FAST: construction heuristics (nearest-neighbor — go to the closest next stop; savings algorithm — merge routes that save distance), then LOCAL SEARCH / metaheuristics (2-opt, or-opt swaps, simulated annealing, genetic/tabu search) that iteratively improve a route, and constraint-aware solvers (respecting capacity/time windows) — trading optimality for speed/scale. ASSIGNMENT considers proximity (assign a delivery to a nearby courier), capacity, time windows, and efficiency (BATCHING nearby deliveries onto one courier's route cuts total travel — e.g. group orders headed the same direction). The optimizer uses real TRAVEL TIMES from a maps/routing engine (not straight-line distance) so routes reflect the actual road network + traffic. OBJECTIVE: minimize total time/distance/cost (and meet time windows, balance courier loads). So formulating it as VRP/TSP and solving with fast HEURISTICS/approximation (since exact is NP-hard), assigning + batching by proximity/capacity/time-windows using real travel times, is the optimization core interviewers probe (recognizing it's NP-hard → heuristic is key)."),
      C("deep_dive", "Deep dive: real-time tracking, ETAs & dynamic re-optimization",
        "Routing isn't a one-shot plan — the defining real-world challenge is DYNAMISM, plus customer-facing tracking/ETAs. DYNAMIC RE-OPTIMIZATION: conditions change CONSTANTLY — NEW orders arrive throughout the day (must be assigned + inserted into a courier's route mid-shift), TRAFFIC shifts (a planned route is now slow), deliveries FAIL or get canceled, couriers go offline — so a STATIC route computed once becomes stale; the system continuously RE-OPTIMIZES: when a new order arrives, decide which courier to assign it to and where to INSERT it in their route (incremental insertion heuristics — cheap re-optimization rather than re-solving everything), and periodically re-evaluate routes as traffic/conditions update. This online/dynamic VRP is harder than the static version (you optimize with incomplete future knowledge). REAL-TIME TRACKING: couriers stream their LOCATION (throttled, battery-aware — the live-location-sharing pattern) to the platform, which (a) shows the CUSTOMER the courier approaching on a map and (b) feeds re-optimization (know where each courier actually is). ETAs: estimate arrival times using the maps/ROUTING engine (road network + live traffic — the maps design) along the planned route — ETAs are continuously updated as the courier moves and conditions change, and shown to customers (a key UX element — 'arriving in 8 min'); accurate ETAs require good traffic-aware routing + prediction. CUSTOMER EXPERIENCE: live tracking + accurate ETAs + notifications ('your order is on the way / arriving') are central to last-mile UX. The maps/routing engine underpins all of it (travel times for optimization, navigation for couriers, ETAs for customers). So continuous dynamic re-optimization (assign + insert new orders, re-route on traffic) + live courier tracking + traffic-aware ETAs (via a maps engine) is the real-time core interviewers probe (the wrong instinct is a one-time static route)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "ROUTING is NP-HARD (VRP/TSP) — exact is infeasible -> heuristics/approximation for good-enough fast solutions; quality vs compute time. DYNAMIC RE-OPTIMIZATION — constant new orders/traffic -> incremental re-optimization (insert/reassign) rather than re-solving from scratch each time; online optimization with incomplete future info. SCALE — many couriers/deliveries across cities -> partition by region/zone, parallelize optimization. REAL-TIME — tracking + ETA updates + re-routing at scale -> live-location ingestion + maps engine. ETA ACCURACY — depends on traffic-aware routing + prediction. Trade-offs: heuristic/approximate routing (fast, scalable, near-optimal — not provably optimal) vs exact optimization (optimal — infeasible at scale/real-time); incremental re-optimization (fast, responsive to changes — may drift from global optimal) vs full re-solve (better solution — slow, disruptive to in-progress routes); batch nearby deliveries (efficient — may delay individual orders) vs one-per-trip (fast per order — inefficient travel); dynamic re-routing (adapts to traffic/orders — churn/complexity) vs fixed routes (stable — stale, inefficient); proximity/capacity/time-window constraints (realistic — harder problem) vs distance-only (simpler — violates real constraints). Closing signal: assign deliveries to couriers (proximity/capacity/time-windows, batching nearby) and optimize multi-stop routes as a VRP/TSP solved with fast HEURISTICS (since exact is NP-hard), using real travel times from a maps/routing engine, with live courier TRACKING, traffic-aware ETAs, and continuous DYNAMIC RE-OPTIMIZATION as new orders/traffic arrive — efficient, adaptive, real-time last-mile delivery."),
      C("deep_dive", "Deep dive: maps engine, food-delivery specifics, scale & operations",
        "Operationally last-mile routing is geo + optimization + real-time logistics. Maps/routing engine: underpins everything — a road-network graph with live TRAFFIC for travel-time estimates (feeding optimization), turn-by-turn navigation for couriers, and ETA computation (the maps/shortest-path design); accuracy of travel times directly drives route quality + ETAs. Assignment models: depending on the domain — pre-planned batch routing (parcel delivery: plan a courier's full day from a depot) vs on-demand dispatch (food/instant delivery: assign each order to a nearby available courier in real time, possibly batching 2-3 nearby orders), which is more like real-time matching (the ride-sharing/matchmaking pattern + routing). Food-delivery specifics: tight time windows (food gets cold), pickup (restaurant) + dropoff (customer) two-leg legs, restaurant prep-time estimation, and batching constraints; on-demand courier supply (gig workers) with their own location/availability. Real-time pipeline: ingest courier locations (live-location, throttled), order events, and traffic; continuously assign/insert/re-route; push ETAs + tracking to customers. Scale: partition by city/zone; optimization runs per-region; many concurrent couriers/orders -> distributed optimization + a real-time event pipeline. Constraints & objectives: capacity, time windows, courier shifts, vehicle types, multi-objective (minimize cost/time, meet SLAs, balance loads, fairness to couriers). Exceptions: failed deliveries, address issues, returns, courier no-shows -> re-assignment. ETA prediction: ML on top of routing for realistic ETAs (historical + traffic + restaurant prep). Customer + courier apps: tracking map, notifications, navigation. Observability: route efficiency (km/stop, on-time rate), ETA accuracy, re-optimization latency, courier utilization, and assignment quality are the SLOs. The spine holds: assignment + heuristic VRP/TSP routing over a traffic-aware maps engine + live tracking + ETA prediction + continuous dynamic re-optimization, partitioned by region, with domain-specific (parcel vs on-demand/food) dispatch."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you order a courier's stops / assign deliveries?' it's TSP (order one courier's stops) / VRP (assign deliveries to couriers + route them) — NP-HARD, so use fast HEURISTICS/approximation (nearest-neighbor, savings, local search/2-opt, metaheuristics), respecting capacity/time-windows, using real travel times. 'Exact optimal?' infeasible at scale/real-time — near-optimal fast is the goal. 'New orders / traffic mid-shift?' DYNAMIC re-optimization — incrementally insert a new order into a courier's route / reassign, and re-route on traffic, rather than a static one-shot plan (online VRP). 'Travel times / navigation / ETA?' a maps/routing engine (road network + live traffic — the maps design) provides them; ETAs update continuously and show to customers. 'Live tracking?' couriers stream location (throttled — the live-location pattern); customers watch the courier approach. 'Batching?' group nearby deliveries onto one courier to cut travel (esp. food: 2-3 nearby orders). 'Scale?' partition by city/zone, optimize per region, real-time event pipeline. 'Food delivery vs parcels?' on-demand dispatch + tight windows + restaurant prep (real-time matching + routing) vs pre-planned depot routes. 'ETA accuracy?' ML + traffic-aware routing. Each returns to the spine: assignment + heuristic VRP/TSP routing (NP-hard) over a maps engine + live tracking + ETAs + continuous dynamic re-optimization."),
    ],
    "Last-mile delivery routing tests ASSIGNMENT of deliveries to couriers (proximity/capacity/time-windows, batching nearby) and multi-stop ROUTE optimization formulated as VRP/TSP solved with fast HEURISTICS (since exact is NP-hard), over a traffic-aware maps/routing engine, PLUS real-time courier TRACKING, traffic-aware ETAs, and continuous DYNAMIC RE-OPTIMIZATION as new orders/traffic/failures arrive — composing geo + optimization + live tracking. The signal is heuristic VRP/TSP assignment+routing + dynamic real-time re-optimization, not a single static shortest-path.",
    [
      G("exact_optimization", "Trying to compute the exact optimal route/assignment.", "Recognize VRP/TSP are NP-hard; use fast heuristics/approximation (nearest-neighbor, savings, local search/metaheuristics) for near-optimal at scale.", "Attempts exhaustive/exact optimization; infeasible for real stop counts in real time."),
      G("static_plan", "Computing routes once and not re-optimizing.", "Continuously re-optimize — insert new orders, reassign, re-route on traffic/failures (online/dynamic VRP); conditions change constantly.", "Plans routes once at shift start; ignores new orders, traffic changes, failures."),
      G("straight_line", "Using straight-line distance instead of real travel times.", "Use a maps/routing engine (road network + live traffic) for travel times, navigation, and ETAs — drives route quality + accurate ETAs.", "Optimizes by Euclidean distance; routes + ETAs don't reflect roads/traffic."),
    ],
    0.7, DIAG.lastmile, "Last-mile delivery routing architecture"),
];

// ── 3 exercises per topic ────────────────────────────────────────────────────
const xpFor = (l) => (l === "warmup" ? 5 : l === "easy" ? 10 : l === "medium" ? 15 : 20);
const diffFor = (l) => (l === "warmup" ? 0.1 : l === "easy" ? 0.2 : l === "medium" ? 0.4 : 0.6);
function pm(moduleId, o) {
  return { trackKey: TRACK_KEY, moduleId, topicId: o.topicId, exerciseId: o.exerciseId,
    position: o.position, level: o.level, type: "pattern_match", title: o.title, scenario: o.scenario,
    instructions: "Pick the best answer.", starterCode: "", expectedSolution: o.correct,
    blanks: [{ options: o.options }], testCases: [{ type: "pattern_match", correct: o.correct, explanation: o.explanation }],
    hints: [], xpReward: xpFor(o.level), difficulty: diffFor(o.level) };
}

